import React, { useCallback, useRef, useState } from 'react';
import { useVoucherFormShellHeight } from '../../../components/form';
import { useNavigate, useParams } from 'react-router-dom';
import { Input, Select, dispatchAppToast } from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../../store/hooks';
import { useVoucherInitData } from '../../../hooks/useVoucherInitData';
import { useMesLsxPermissions } from '../../../hooks/useMesPermissions';
import { useUnsavedChangesGuard } from '../../../hooks/useUnsavedChangesGuard';
import { sxService } from '../../../services/sx/sxService';
import { DocumentFormHeader } from '../../../components/layout';
import { CatalogDocumentHistory } from '../../../components/catalog';
import { mesDocumentTypes } from '../../../config/documentHistoryClients';
import { UnsavedChangesModal } from '../../../components/form/UnsavedChangesModal';
import { ContractSearchField } from '../../../components/search/ContractSearchField';
import { lsxPageLabels as labels } from '../../../constants/lsxPageLabels';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import df from '../../../styles/documentForm.module.css';

const emptyForm = {
  orderDate: new Date().toISOString().slice(0, 10),
  contractCode: '',
  productCode: '',
  unitCode: '',
  orderQty: 1,
  plannedStartDate: '',
  plannedEndDate: '',
  description: '',
};

type FieldErrors = {
  productCode?: string;
  orderQty?: string;
};

const LsxFormPage: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const isEdit = Boolean(id);
  const isNew = !isEdit;
  const navigate = useNavigate();
  const dispatch = useAppDispatch();

  const initFormName = isEdit ? 'edit-production-order' : 'create-production-order';
  const { unitOptions } = useVoucherInitData(initFormName);
  const perms = useMesLsxPermissions();
  const formReadOnly = isEdit && !perms.canUpdate;
  const canSave = isNew ? perms.canCreate : perms.canUpdate;
  const unitOpts = [{ value: '', label: '— ĐVT —' }, ...unitOptions];

  const [form, setForm] = useState(emptyForm);
  const [fieldErrors, setFieldErrors] = useState<FieldErrors>({});
  const [contractCustomerName, setContractCustomerName] = useState('');
  const [code, setCode] = useState('');
  const [legacyId, setLegacyId] = useState<string | null>(null);
  const [loading, setLoading] = useState(isEdit);
  const [saving, setSaving] = useState(false);
  const [isDirty, setIsDirty] = useState(false);
  const loadedRef = useRef(!isEdit);
  const shellRef = useRef<HTMLDivElement>(null);
  useVoucherFormShellHeight(shellRef);

  const markDirty = useCallback(() => {
    if (loadedRef.current && !formReadOnly) setIsDirty(true);
  }, [formReadOnly]);

  const {
    showUnsavedModal,
    guardedAction,
    confirmLeave,
    cancelLeave,
  } = useUnsavedChangesGuard(isDirty, !formReadOnly);

  const patchFieldError = useCallback((field: keyof FieldErrors, message?: string) => {
    setFieldErrors(prev => {
      if (!message) {
        const next = { ...prev };
        delete next[field];
        return next;
      }
      return { ...prev, [field]: message };
    });
  }, []);

  const set = (key: keyof typeof emptyForm, value: string | number) => {
    markDirty();
    setForm(prev => ({ ...prev, [key]: value }));
  };

  React.useEffect(() => {
    if (!id) return;
    let cancelled = false;
    setLoading(true);
    loadedRef.current = false;
    const t = setTimeout(() => {
      sxService
        .getProductionOrder(id)
        .then(o => {
          if (!cancelled) {
            setCode(o.code);
            setLegacyId(o.legacyId ?? null);
            setForm({
              orderDate: o.orderDate.slice(0, 10),
              contractCode: o.contractCode ?? '',
              productCode: o.productCode,
              unitCode: o.unitCode,
              orderQty: o.orderQty,
              plannedStartDate: o.plannedStartDate?.slice(0, 10) ?? '',
              plannedEndDate: o.plannedEndDate?.slice(0, 10) ?? '',
              description: o.description ?? '',
            });
            setIsDirty(false);
            loadedRef.current = true;
          }
        })
        .catch(err => {
          if (!cancelled) {
            dispatchAppToast(dispatch, {
              message: getApiErrorMessage(err, labels.loadFormError),
              type: 'error',
            });
          }
        })
        .finally(() => {
          if (!cancelled) setLoading(false);
        });
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, [id, dispatch]);

  const validate = (): boolean => {
    const next: FieldErrors = {};
    if (!isEdit && !form.productCode.trim()) {
      next.productCode = labels.productRequired;
    }
    if (!form.orderQty || form.orderQty <= 0) {
      next.orderQty = labels.qtyRequired;
    }
    setFieldErrors(next);
    if (Object.keys(next).length > 0) {
      const first = document.querySelector('[data-validation-target="true"]');
      first?.scrollIntoView({ behavior: 'smooth', block: 'center' });
      return false;
    }
    return true;
  };

  const handleSave = async () => {
    if (!validate()) return;
    setSaving(true);
    try {
      const payload = {
        orderDate: form.orderDate,
        contractCode: form.contractCode || undefined,
        productCode: form.productCode.trim(),
        unitCode: form.unitCode.trim() || 'CAI',
        orderQty: Number(form.orderQty),
        plannedStartDate: form.plannedStartDate || undefined,
        plannedEndDate: form.plannedEndDate || undefined,
        description: form.description || undefined,
      };
      if (isEdit && id) {
        await sxService.updateProductionOrder(id, {
          contractCode: payload.contractCode,
          orderQty: payload.orderQty,
          plannedStartDate: payload.plannedStartDate,
          plannedEndDate: payload.plannedEndDate,
          description: payload.description,
        });
        dispatchAppToast(dispatch, { message: labels.updateSuccess, type: 'success' });
      } else {
        await sxService.createProductionOrder(payload);
        dispatchAppToast(dispatch, { message: labels.createSuccess, type: 'success' });
      }
      navigate('/sx/lsx');
    } catch (err: unknown) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(err, labels.saveError),
        type: 'error',
      });
    } finally {
      setSaving(false);
    }
  };

  if (loading) return <div className={df.loading}>Đang tải...</div>;

  return (
    <div
      ref={shellRef}
      className={df.pageVoucher}
      data-voucher-form-shell
      data-testid="erp-lsx-form-shell"
    >
      <UnsavedChangesModal
        isOpen={showUnsavedModal}
        onStay={cancelLeave}
        onLeave={confirmLeave}
        data-testid="erp-lsx-unsaved-modal"
      />
      <div className={df.pageFormHeader}>
        <DocumentFormHeader
          onBack={() => guardedAction(() => navigate('/sx/lsx'))}
          title={isEdit ? `Sửa lệnh SX ${code}` : 'Tạo lệnh sản xuất'}
          legacyId={legacyId}
          legacyIdLabel={labels.legacyIdLabel}
          isNew={isNew}
          isReadOnly={!canSave}
          saving={saving}
          saveLabel="Tạo lệnh SX"
          saveEditLabel="Lưu thay đổi"
          onSave={canSave ? handleSave : undefined}
          extraActions={
            isEdit && id && perms.canRead ? (
              <CatalogDocumentHistory
                testIdPrefix="erp-lsx"
                documentType={mesDocumentTypes.productionOrder}
                documentId={id}
                documentCode={code}
              />
            ) : undefined
          }
        />
      </div>
      <div className={df.pageFormScroll} data-testid="erp-lsx-form-scroll">
      <div className={df.section}>
        <h2 className={df.sectionTitle}>Thông tin lệnh</h2>
        <div className={df.row4}>
          <div className={df.field}>
            <label className={df.label}>Ngày lệnh *</label>
            <Input
              type="date"
              value={form.orderDate}
              onChange={e => set('orderDate', e.target.value)}
              disabled={isEdit}
            />
          </div>
          <div className={df.field}>
            <label className={df.label}>Số tham chiếu (HĐ)</label>
            <ContractSearchField
              contractCode={form.contractCode}
              customerName={contractCustomerName}
              onSelect={(c, name) => {
                markDirty();
                set('contractCode', c);
                setContractCustomerName(name);
              }}
              onClear={() => {
                markDirty();
                set('contractCode', '');
                setContractCustomerName('');
              }}
            />
          </div>
          <div
            className={df.field}
            data-validation-target={fieldErrors.productCode ? 'true' : undefined}
          >
            <label className={df.label}>Mã sản phẩm *</label>
            <Input
              value={form.productCode}
              onChange={e => {
                patchFieldError('productCode');
                set('productCode', e.target.value);
              }}
              disabled={isEdit}
              error={fieldErrors.productCode}
              required={!isEdit}
            />
          </div>
          <div className={df.field}>
            <label className={df.label}>ĐVT</label>
            <Select
              value={form.unitCode}
              onChange={e => set('unitCode', e.target.value)}
              options={unitOpts}
              disabled={isEdit}
            />
          </div>
        </div>
        <div className={df.row4}>
          <div
            className={df.field}
            data-validation-target={fieldErrors.orderQty ? 'true' : undefined}
          >
            <label className={df.label}>Số lượng *</label>
            <Input
              type="number"
              min={1}
              value={String(form.orderQty)}
              onChange={e => {
                patchFieldError('orderQty');
                set('orderQty', Number(e.target.value));
              }}
              error={fieldErrors.orderQty}
              required
            />
          </div>
          <div className={df.field}>
            <label className={df.label}>Ngày bắt đầu KH</label>
            <Input
              type="date"
              value={form.plannedStartDate}
              onChange={e => set('plannedStartDate', e.target.value)}
            />
          </div>
          <div className={df.field}>
            <label className={df.label}>Ngày kết thúc KH</label>
            <Input
              type="date"
              value={form.plannedEndDate}
              onChange={e => set('plannedEndDate', e.target.value)}
            />
          </div>
          <div className={df.field}>
            <label className={df.label}>Ghi chú</label>
            <Input
              value={form.description}
              onChange={e => set('description', e.target.value)}
            />
          </div>
        </div>
      </div>
      </div>
    </div>
  );
};

export default LsxFormPage;
